**free
/if NOT DEFINED(flda0100_t)
/define flda0100_t
//===============================================================*
//  QDBRTVFD API - FLDA0100                                      *
// ============================================================= *
dcl-ds flda0100_t qualified;
  // File name
  file      char(10);
  // Library name
  lib       char(10);
  // Field name
  name      char(10);
  // Data type
  type      char(1);
  // Use
  use       char(1);
  // Output buffer position
  outBufPos int(10);
  // Input buffer position
  inBufPos  int(10);
  // Field length in bytes
  length    int(10);
  // Digits
  digits    int(10);
  // Decimal position
  decPos    int(10);
  // Field text description
  text      char(50);
  // Edit code
  edtC      char(2);
  // Edit word length
  edtWLen   bindec(9);
  // Edit word
  edtW      char(64);
  // Column heading 1
  colHdg1   char(20);
  // Column heading 2
  colHdg2   char(20);
  // Column heading 3
  colHdg3   char(20);
  // Date and time format
  datTimFmt char(4);
  // Date and time separator
  datTimSep char(1);
end-ds;

/endif

