//  File Scope Array (Qdb_Qdbfb)
dcl-ds Qdb_Qdbfb_t qualified based(pDummy);
  Reserved_48 char(48);
  Qdbfbf      char(10);
  Qdbfbfl     char(10);
  Qdbft       char(10);
