/copy QRTVFLDA,PRTVFLDA

//  *ENTRY list
dcl-pr RTVFLDA_T extpgm('RTVFLDA_T6');
  gi_file    char(10) const;
  gi_fldName char(10) const;
end-pr;

//  Internal prototypes
dcl-pr main;
  i_file    char(10) const;
  i_fldName char(10) const;
end-pr;

//*******************************************************************
//  Program Entry Point
//*******************************************************************
dcl-pi RTVFLDA_T;
  gi_file    char(10) const;
  gi_fldName char(10) const;
end-pi;
//-------------------------------------------------------------------
main(gi_file: gi_fldName);

*inlr = *ON;


//==================================================================*
//  Main procedure
//==================================================================*
dcl-proc main export;
  dcl-pi *n;
    i_file    char(10) const;
    i_fldName char(10) const;
  end-pi;

  //  Local fields
  dcl-s isOK ind inz;
  dcl-s handle like(fldDct_handle_t) inz;

  dcl-ds msg likeds(msg_t) inz;
  dcl-ds errMsg likeds(msg_t) inz;
  dcl-ds flda0340 likeds(flda0340_t) inz;
  dcl-s default char(128) based(flda0340.pDftValue);
  //-------------------------------------------------------------------

  errMsg = f_newMsg(cMSG_ID_OK);

  dou '1';

    // Open dictionary
    isOK = f_fldDct_new(i_file: '*LIBL': '*FIRST': handle: msg);

    // Get attributes of i_fldName
    isOK = f_FldDct_rtvFldAtr(handle: i_fldName: flda0340: 'FLDA0340');
    if (isOK);
      select;
      when (flda0340.isNullDft);
        msg = f_newMsg('CPF9897'
                       : 'Field ' + %trim(flda0340.name) +
                         ', Default is NULL');
      when (flda0340.isCurrTime);
        msg = f_newMsg('CPF9897'
                       : 'Field ' + %trim(flda0340.name) +
                         ', Default is CURRENT_TIME');
      when (flda0340.hasDtfKeyword);
        if (%subst(default: 1: flda0340.lenDftValue) = 'USER');
          msg = f_newMsg('CPF9897'
                         : 'Field ' + %trim(flda0340.name) +
                           ', Default is CURRENT_USER');
        else;
          msg = f_newMsg('CPF9897'
                      : 'Field ' + %trim(flda0340.name) +
                        ', Default is ' +
                           %subst(default: 1: flda0340.lenDftValue));
        endif;
      other;
        msg = f_newMsg('CPF9897'
                       : 'Field ' + %trim(flda0340.name) +
                         ', has no default value');
      endsl;
      f_sndPgmMsg(msg: cMsg_Prv: cMsg_ToCtlBdy);
    else;
      errMsg = f_newMsg('CPF9898'
                     : 'Field not found'
                     : cMSG_ESCAPE);
      leave;
    endif;

  enddo;

  // Close dictionary
  isOK = f_FldDct_delete(handle);

  if (errMsg.ID <> cMSG_ID_OK);
    f_sndPgmMsg(errMsg: cMsg_Prv: cMsg_ToCtlBdy);
  endif;

  return;


end-proc;

**free
//=====================================================================*
//  Author  :  Thomas Raddatz                                          *
//  Date    :  25.09.2002                                              *
//  E-mail  :  thomas.raddatz@Tools400.de                              *
//  Homepage:  www.tools400.de                                         *
//=====================================================================*
//                                                                     *
//  This software is free software, you can redistribute it and/or     *
//  modify it under the terms of the GNU General Public License (GPL)  *
//  as published by the Free Software Foundation.                      *
//                                                                     *
//  See GNU General Public License for details.                        *
//          http://www.opensource.org                                  *
//          http://www.opensource.org/licenses/gpl-license.html        *
//                                                                     *
//=====================================================================*
//  Test file used when adding format FLDA0340:                        *
//                                                                     *
//     CREATE TABLE QTEMP.TEST (                                       *
//      DATE_ DATE,                                                    *
//      TIME_ TIME NOT NULL WITH DEFAULT CURRENT_TIME,                 *
//      TIMESTAMP_ TIMESTAMP WITH DEFAULT NULL,                        *
//      HEX_ CHAR(10) NOT NULL WITH DEFAULT x'C49695819384'            *
//      BOOL_ CHAR(1) NOT NULL WITH DEFAULT '0'                        *
//         CHECK (BOOL_ IN ('0', '1'))                                 *
//      ) RCDFMT FTEST2                                                *
//                                                                     *
//  Values of 'Qdb_Qddfdft.Qddfdfta':                                  *
//     date        :  no default                                       *
//     time_       :  x'04'        expected: x'05'   dft + time        *
//     timestamp_  :  x'20'        expected: x'21'   dft + null        *
//     hex_        :  x'40'        expected: x'41'   dft + hex literal *
//     bool_       :  x'00'        expected: x'01'   dft               *
//                                                                     *
//  Bit 'Qddfdftk' of 'Qdb_Qddfdft.Qddfdfta' is missing for fields     *
//  with default values, isn't it?                                     *
//                                                                     *
//     R FTEST                                                         *
//       DATE_           L         ALWNULL                             *
//       TIME_           T                                             *
//       TIMESTAMP_      Z         ALWNULL DFT(*NULL)                  *
//       HEX_          10A         DFT(X'C4969581938440404040')        *
//       BOOL_          1A         DFT('0') VALUES('1' '0')            *
//                                                                     *
//  Values of 'Qdb_Qddfdft.Qddfdfta':                                  *
//     date        :  no default                                       *
//     time_       :  no default   though initialized to CURRENT_TIME  *
//     timestamp_  :  x'20'        expected: x'21'   dft + null        *
//     hex_        :  x'40'        expected: x'41'   dft + hex literal *
//     bool_       :  x'00'        expected: x'01'   dft               *
//                                                                     *
//=====================================================================*
//  History:                                                           *
//                                                                     *
//  Datum       Name           nderung                                 *
//  ----------  ------------  ---------------------------------------  *
//  17.02.2006  Th.Raddatz    Fixed problem that a wrong TEXT was      *
//                            returned, when there is not field text.  *
//                            Introduced format FLDA0310 to get        *
//                            information about 'variable length'      *
//                            fields.                                  *
//                                                                     *
//  21.02.2006  Th.Raddatz    Enabled data type CHARACTER (variable    *
//                            length).                                 *
//                                                                     *
//  17.04.2007  Th.Raddatz    Changed i_fldName of f_FldDct_rtvFldAtr  *
//                            to 258A *VARSIZE.                        *
//                                                                     *
//  10.08.2007  Th.Raddatz    Enabled data type GRAPHIC.               *
//                                                                     *
//  10.10.2007  Th.Raddatz    Fixed problem that column heading        *
//                            contained garbage when a field did       *
//                            not have a column heading.               *
//                                                                     *
//  24.09.2008  Th.Raddatz    Fixed problem that 'length' was not      *
//                            properly set for VARLEN fields.          *
//                            Actually 'isVarying' was not correctly   *
//                            set.                                     *
//                                                                     *
//  26.09.2008  Th.Raddatz    Fixed problem that o_isDone was not      *
//                            set by f_FldDct_delete().                *
//                                                                     *
//  04.12.2008  Th.Raddatz    f_FldDct_rtvFldAtr() now returns the     *
//                            correct entry if a given alias name      *
//                            is shorter than 10 characters.           *
//                            Fixed call to f_rmvQuotes(). Parameters  *
//                            had to be reversed.                      *
//                                                                     *
//  31.10.2012  Th.Raddatz    Added new format FLDA0330.               *
//                                                                     *
//  17.10.2013  Th.Raddatz    Added new format FLDA0340.               *
//                                                                     *
//  03.02.2015  Th.Raddatz    Added field type LOB. (cFLDDCT_TYPE_LOB) *
//                                                                     *
//  08.0142021  Th.Raddatz    Added new format FLDA0350.               *
//                                                                     *
//=====================================================================*
//   >>PRE-COMPILER<<                                                  *
//     >>CRTCMD<<  CRTRPGMOD    MODULE(&LI/&OB) +                      *
//                              SRCFILE(&SL/&SF) +                     *
//                              SRCMBR(&SM);                           *
//     >>COMPILE<<                                                     *
//       >>PARM<< OPTION(*EVENTF);                                     *
//       >>PARM<< TRUNCNBR(*NO);                                       *
//       >>PARM<< DBGVIEW(*LIST);                                      *
//     >>END-COMPILE<<                                                 *
//     >>EXECUTE<<                                                     *
//   >>END-PRE-COMPILER<<                                              *
//=====================================================================*
ctl-opt nomain;
ctl-opt extbinint(*yes) bnddir('QC2LE');
ctl-opt datfmt(*iso) timfmt(*iso) debug(*yes);
/copy QRTVFLDA,COPYRIGHT
//=====================================================================*
//
// ---------------------------------------------
//  Prototypes of exported procedures
// ---------------------------------------------
/copy QRTVFLDA,PRTVFLDA

// ---------------------------------------------
//  Reference fields
// ---------------------------------------------

//  Handle data
dcl-ds handle_t based(pDummy) qualified;
  hFild0100  pointer;
  hFild0200  pointer;
  file       char(10);
  lib        char(10);
  lastFldNum int(10);
  lastFldPtr pointer;
end-ds;

// ---------------------------------------------
//  Prototypes of private procedures
// ---------------------------------------------
dcl-pr rtvFileD pointer;
  io_file     char(10);
  io_lib      char(10);
  i_rcdFormat char(10) const;
  i_format    char(10) const;
  o_msg       likeds(msg_t);
end-pr;

dcl-pr f_intToExtDataType char(1);
  i_intDataType char(2) const;
end-pr;

dcl-pr f_intToExtUsage char(1);
  i_intUsage char(1) const;
end-pr;

dcl-pr f_intToExtDatTimFmt char(4);
  i_intDataType char(2) const;
  i_intFmt      char(1) const;
end-pr;

dcl-pr f_intToExtDatTimSep char(1);
  i_intDataType char(2) const;
  i_intSep      char(1) const;
end-pr;

// ---------------------------------------------
//  Prototypes of external procedures
// ---------------------------------------------
/copy QRTVFLDA,QDBRTVFD                      Retrieve Database File Description (QDBRTVF

//  Get String Information (CEEGSI) API
dcl-pr CEEGSI extproc('CEEGSI');
  i_posNr    int(10) const;
  o_dataType int(10);
  o_currLen  int(10);
  o_maxLen   int(10);
  o_fc       char(12) options(*omit);
end-pr;

//  Global constants
dcl-c cDOUBLE_QUOTE '"';

//==================================================================*
//  Create Field Attributes Dictionary
//==================================================================*

dcl-proc f_FldDct_new export;
  dcl-pi *n ind;
    i_file      char(10) const;
    i_lib       char(10) const;
    i_rcdFormat char(10) const;
    o_handle    like(fldDct_handle_t);
    o_msg       likeds(msg_t) options(*nopass);
  end-pi;

  //  Return value
  dcl-s o_isDone ind inz(cFalse);

  //  Positions of optional parameters
  dcl-c cpMsg 5;

  //  Handle data
  dcl-ds handle likeds(handle_t) based(pHandle);

  //  Local fields
  dcl-s isBuffer ind inz(cFalse);
  dcl-s bufferSize int(10) inz;

  dcl-ds msg likeds(msg_t) inz;
  dcl-ds qFile likeds(qObj_t) inz;
  dcl-s pFild0100 pointer inz;
  dcl-s pFild0200 pointer inz;
  // ---------------------------------------------------------


  // Initialize return values
  o_isDone = cFalse;

  clear qFile;
  qFile.name = i_file;
  qFile.lib = i_lib;

  pFild0100 = *null;
  pFild0200 = rtvFileD(
                 qFile.name: qFile.lib: i_rcdFormat: 'FILD0200': msg);

  if (pFild0200 <> *null);
    pFild0100 = rtvFileD(
                   qFile.name: qFile.lib: i_rcdFormat: 'FILD0100': msg);
  endif;

  // If the file description is available ...
  if (pFild0200 <> *null);
    // ... then allocate handle buffer and
    //     return the handle
    pHandle = %alloc(%size(handle));
    handle.hFild0100    = pFild0100;
    handle.hFild0200    = pFild0200;
    handle.file       = qFile.name;
    handle.lib        = qFile.lib;
    handle.lastFldNum = 0;
    handle.lastFldPtr = *NULL;
    o_handle = pHandle;
    o_isDone = cTrue;
  else;
    // ... else deallocate buffer and
    //     set return value to NULL
    if   isBuffer;
      if (pFild0100 <> *null);
        dealloc(N) pFild0100;
      endif;
      dealloc(N) pFild0200;
      isBuffer   = cFalse;
      bufferSize = 0;
    endif;
    o_handle = *NULL;
    o_isDone = cFalse;
  endif;

  if (%parms >= cpMsg);
    o_msg = msg;
  endif;

  return   o_isDone;


end-proc;

//==================================================================*

//==================================================================*

dcl-proc rtvFileD;
  dcl-pi *n pointer;
    io_file     char(10);
    io_lib      char(10);
    i_rcdFormat char(10) const;
    i_format    char(10) const;
    o_msg       likeds(msg_t);
  end-pi;

  dcl-s bufferSize int(10) inz;
  dcl-ds buffer based(pBuffer) qualified;
    bytRet int(10);
    bytAvl int(10);
  end-ds;
  dcl-ds qFile likeds(qObj_t) inz;
  dcl-ds qRetFile likeds(qObj_t) inz;
  dcl-ds errCode likeds(errCode_t) inz;

  clear o_msg;

  // Retrieve file description ...
  dou '1';

    // ... allocate memory
    bufferSize = %size(buffer);
    pBuffer    = %alloc(bufferSize);

    // ... determine size of memory actually needed
    qFile.name = io_file;
    qFile.lib  = io_lib;
    errCode    = f_newApiErrCode(cTrue);
    QDBRTVFD(buffer: bufferSize : qRetFile: i_format:
             qFile : i_rcdFormat: '0'     : '*LCL'    :
             '*EXT': errCode);
    if (f_isAPIError(errCode));
      o_msg = f_cvtApiErrCodeToMsg(errCode);
      leave;
    else;

      // ... retrieve file description
      //     (incrementing buffer size as needed; strange API)
      qFile = qRetFile;
      dow (buffer.bytAvl > buffer.bytRet);
        bufferSize = buffer.bytAvl;
        pBuffer = %realloc(pBuffer: bufferSize);
        QDBRTVFD(Buffer : bufferSize : qRetFile: i_format:
                 qFile  : i_rcdFormat: '0'     : '*LCL'    :
                 '*EXT' : errCode);
        if (f_isAPIError(errCode));
          o_msg = f_cvtApiErrCodeToMsg(errCode);
          leave;
        else;
          clear o_msg;
          io_file = qRetFile.name;
          io_lib = qRetFile.lib;
          return pBuffer;
        endif;
      enddo;

    endif;
  enddo;

  if (pBuffer <> *null);
    dealloc(N) pBuffer;
  endif;

  return *null;

end-proc;

//==================================================================*
//  Delete Field Attributes Dictionary
//==================================================================*

dcl-proc f_FldDct_delete export;
  dcl-pi *n ind;
    io_handle like(fldDct_handle_t);
  end-pi;

  //  Return value
  dcl-s o_isDone ind inz(cFalse);

  //  Handle data
  dcl-ds handle likeds(handle_t) based(pHandle);
  // ---------------------------------------------------------


  // Get access to handle data
  pHandle = io_handle;

  // Free file description buffers
  if (handle.hFild0100 <> *null);
    dealloc(N) handle.hFild0100;
  endif;

  dealloc(N)   handle.hFild0200;

  // Initialize handle data
  clear   handle;
  handle.hFild0200  = *NULL;
  handle.file     = '';
  handle.lib      = '';

  // Deallocate handle buffer
  dealloc(N)   pHandle;

  // Return handle
  io_handle = pHandle;

  o_isDone = cTrue;

  return   o_isDone;


end-proc;

//==================================================================*
//  Retrieve Field Attributes from Dictionary
//==================================================================*

dcl-proc f_FldDct_rtvFldAtr export;
  dcl-pi *n ind opdesc;
    i_handle  like(fldDct_handle_t) const;
    i_fldName char(258) options(*varsize) const;
    o_data    char(2048) options(*varsize);
    i_format  char(8) options(*nopass) const;
  end-pi;

  //  Return value
  dcl-s o_isDone ind inz(cFalse);

  //  Positions of (optional) parameters
  dcl-c cpFldName 2;
  dcl-c cpData 3;
  dcl-c cpFormat 4;

  //  Optional parameter fields
  dcl-s format like(i_format) inz;

  //  Handle
  dcl-ds handle likeds(handle_t) based(pHandle);

  //  File Definition Header (Qdb_Qdbfh)
  dcl-ds Qdb_Qdbfh likeds(Qdb_Qdbfh_t) based(pQdb_Qdbfh);

  //  Format Definition Header (Qdb_Qddfmt)
  dcl-ds Qdb_Qddfmt likeds(Qdb_Qddfmt_t) based(pQdb_Qddfmt);

  //  Field Header (Qdb_Qddffld)
  dcl-ds Qdb_Qddffld likeds(Qdb_Qddffld_t) based(pQdb_Qddffld);

  //  Alias name structure (Qdb_Qddfalis)
  dcl-ds Qdb_Qddfalis likeds(Qdb_Qddfalis_t) based(pQdb_Qddfalis);

  //  Reference Information (Qdb_Qddfrefi)
  dcl-ds Qdb_Qddfrefi likeds(Qdb_Qddfrefi_t) based(pQdb_Qddfrefi);

  //  Field Text (Qdb_Qddfftxt)
  dcl-ds Qdb_Qddfftxt likeds(Qdb_Qddfftxt_t) based(pQdb_Qddfftxt);

  //  Column Heading Information (Qdb_Qddfcolh)
  dcl-ds Qdb_Qddfcolh likeds(Qdb_Qddfcolh_t) based(pQdb_Qddfcolh);

  //  Edit Code/Edit Word Information (Qdb_Qddfedcw)
  dcl-ds Qdb_Qddfedcw likeds(Qdb_Qddfedcw_t) based(pQdb_Qddfedcw);

  //  Default Value Description Information (Qdb_Qddfdft)
  dcl-ds Qdb_Qddfdft likeds(Qdb_Qddfdft_t) based(pQdb_Qddfdft);

  //  Identity Column Information (Qdb_Qddfidcl)
  dcl-ds Qdb_Qddfidcl likeds(Qdb_Qddfidcl_t) based(pQdb_Qddfidcl);
  //  Local fields
  dcl-s isFound ind inz;
  dcl-s isVarying ind inz;
  dcl-s fldNum int(20) inz;
  dcl-s y int(20) inz;
  dcl-s blankText like(Qdb_Qddfftxt.Qddfftxt);
  dcl-s fldName varchar(258) inz;
  dcl-s longFldName varchar(258) inz;

  dcl-ds FLDA0100 likeds(flda0100_t);
  dcl-ds FLDA0200 likeds(flda0200_t);
  dcl-ds FLDA0300 likeds(flda0300_t);
  dcl-ds FLDA0310 likeds(flda0310_t);
  dcl-ds FLDA0320 likeds(flda0320_t);
  dcl-ds FLDA0330 likeds(flda0330_t);
  dcl-ds FLDA0340 likeds(flda0340_t);
  dcl-ds FLDA0350 likeds(flda0350_t);

  //  String information of i_fldName
  dcl-ds si_i_fldName qualified;
    dataType int(10);
    currLen  int(10);
    maxLen   int(10);
  end-ds;

  //  String information of o_data
  dcl-ds si_o_data qualified;
    dataType int(10);
    currLen  int(10);
    maxLen   int(10);
  end-ds;
  //-------------------------------------------------------------------

  // Get optional parameters
  if   %parms >= cpFormat;
    format = i_format;
  else;
    format = 'FLDA0100';
  endif;

  // Get string information of i_fldName
  CEEGSI(cpFldName:
         si_i_fldName.dataType:
         si_i_fldName.currLen: si_i_fldName.maxLen: *omit);

  fldName = %trimR(%subst(i_fldName: 1: si_i_fldName.currLen));

  // Get string information of o_data
  CEEGSI(cpData:
         si_o_data.dataType: si_o_data.currLen: si_o_data.maxLen: *omit);

  // Get access to handle data
  pHandle = i_handle;

  // Get access to File Definition Template header"
  pQdb_Qdbfh = handle.hFild0100;

  // Get access to "Format Definition Header"
  pQdb_Qddfmt = handle.hFild0200;

  // Initialize helper fields
  isFound        = cFalse;

  // Optimization for cFLDDCT_FLD_NEXT
  if   fldName = cFLDDCT_FLD_NEXT;
    y = handle.lastFldNum;
    // get access to "Field Header" of last field returned
    // to get entry length
    pQdb_Qddffld = handle.lastFldPtr;
  else;
    y = 1;
    // get access to "Field Header" of first field
    // to get entry length
    pQdb_Qddffld = %addr(Qdb_Qddfmt.Qddffldx);
  endif;

  // Spin through the file format definition
  // and look for the field requested
  for   fldNum = y to Qdb_Qddfmt.Qddffldnum;

    // Get access to alias field name
    longFldName = '';
    if (Qdb_Qddffld.Qddfxals <> 0);
      pQdb_Qddfalis = pQdb_Qddffld + Qdb_Qddffld.Qddfxals;
      if (Qdb_Qddfalis.Qddfalsl > 0);
        longFldName = %trimR(%subst(Qdb_Qddfalis.Qddfalsn
                                    : 1: Qdb_Qddfalis.Qddfalsl));
        longFldName = f_rmvQuotes(longFldName: cDOUBLE_QUOTE);
      endif;
    endif;

    if longFldName = '';
      longFldName = %trimR(Qdb_Qddffld.Qddffldi);
    endif;

    // Process special value ...
    select;
    // ... FIRST
    when   (fldName = cFLDDCT_FLD_FIRST) and
           (fldNum = 1);
      isFound = cTrue;
      leave;
    // ... LAST
    when   (fldName = cFLDDCT_FLD_LAST)  and
           (fldNum = Qdb_Qddfmt.Qddffldnum);
      isFound = cTrue;
      leave;
    // ... NEXT
    when   (fldName = cFLDDCT_FLD_NEXT)  and
           (fldNum = handle.lastFldNum + 1);
      isFound = cTrue;
      leave;
    // ... PREVIOUS
    when   (fldName = cFLDDCT_FLD_PREV)  and
           (fldNum = handle.lastFldNum - 1);
      isFound = cTrue;
      leave;
    // ... and a named field
    other;
      if   (fldName = longFldName or
            fldName = %trimR(Qdb_Qddffld.Qddffldi));
        isFound = cTrue;
        leave;
      endif;
    endsl;

    // get access to next field in list
    pQdb_Qddffld = pQdb_Qddffld + Qdb_Qddffld.Qddfdefl;
  endfor;

  // If the field could not be found, ...
  if   not isFound;
    // ... then return BAD
    o_isDone = cFalse;
    %subst(o_data: 1: si_o_data.currLen) = '';
  else;
    // ... else return OK and field data
    o_isDone = cTrue;
    %subst(o_data: 1: si_o_data.currLen) = '';

    // Get access to "Reference Information"
    if   Qdb_Qddffld.Qddfrefd > 0;
      pQdb_Qddfrefi = pQdb_Qddffld + Qdb_Qddffld.Qddfrefd;
    else;
      pQdb_Qddfrefi = *NULL;
    endif;

    // Get access to "Edit Code/Edit Word Information"
    if   Qdb_Qddffld.Qddfedtl = 0;
      pQdb_Qddfedcw = *NULL;
    else;
      pQdb_Qddfedcw = pQdb_Qddffld + Qdb_Qddffld.Qddfedtd;
    endif;

    // Get access to "Field Text"
    if Qdb_Qddffld.Qddftxtd = 0;
      pQdb_Qddfftxt = %addr(blankText);
    else;
      pQdb_Qddfftxt = pQdb_Qddffld + Qdb_Qddffld.Qddftxtd;
    endif;

    // Get access to "Default Value Information"
    if Qdb_Qddffld.Qddfdftd = 0;
      pQdb_Qddfdft = *NULL;
    else;
      pQdb_Qddfdft = pQdb_Qddffld + Qdb_Qddffld.Qddfdftd;
    endif;

    // Get access to "Column Heading Information"
    if Qdb_Qddffld.Qddfchd = 0;
      pQdb_Qddfcolh = *NULL;
    else;
      pQdb_Qddfcolh = pQdb_Qddffld + Qdb_Qddffld.Qddfchd;
    endif;

    // Determine if the field is a VARYING field
    if (f_isBitOn(x'20': Qdb_Qddffld.Qddffldst2)
        or Qdb_Qddffld.Qddfftyp = X'8004'    // = var character // Hack until PTF
        or Qdb_Qddffld.Qddfftyp = X'8005');  // = var graphic   // is available
      isVarying = cTrue;
    else;
      isVarying = cFalse;
    endif;

    // Set return data values
    clear   FLDA0100;
    FLDA0100.file      = handle.file;
    FLDA0100.lib       = handle.lib;
    FLDA0100.name      = Qdb_Qddffld.Qddffldi;
    FLDA0100.type      = f_intToExtDataType(Qdb_Qddffld.Qddfftyp);
    FLDA0100.use       = f_intToExtUsage(Qdb_Qddffld.Qddffiob);
    FLDA0100.outBufPos = Qdb_Qddffld.Qddffobo + 1;
    FLDA0100.inBufPos  = Qdb_Qddffld.Qddffibo + 1;

    if isVarying;
      FLDA0100.length    = Qdb_Qddffld.Qddffldb - 2;
    else;
      FLDA0100.length    = Qdb_Qddffld.Qddffldb;
    endif;

    FLDA0100.digits    = Qdb_Qddffld.Qddffldd;
    FLDA0100.decPos    = Qdb_Qddffld.Qddffldp;
    FLDA0100.text      = Qdb_Qddfftxt.Qddfftxt;

    // If there is no field edit code, ...
    if   pQdb_Qddfedcw = *NULL;
      // ... then clear the related fields
      FLDA0100.edtc    = '';
      FLDA0100.edtWLen = 0;
      FLDA0100.edtW    = '';
    else;
      // ... else
      //     If it is an edit word, ...
      if   Qdb_Qddffld.Qddfedtl > 16;                // => EditWord
        // ... then return edit word information
        FLDA0100.edtc    = '';
        FLDA0100.edtWLen = Qdb_Qddffld.Qddfedtl - 16;
        FLDA0100.edtW    = %subst(Qdb_Qddfedcw.Qddfewd :
                                  1                    :
                                  FLDA0100.edtWLen     );
      else;
        //    ... else return edit code information
        FLDA0100.edtc    = Qdb_Qddfedcw.Qddfecdi;
        FLDA0100.edtWLen = 0;
        FLDA0100.edtW    = '';
      endif;
    endif;

    if pQdb_Qddfcolh = *NULL;
      FLDA0100.colHdg1 = '';
      FLDA0100.colHdg2 = '';
      FLDA0100.colHdg3 = '';
    else;
      FLDA0100.colHdg1 = Qdb_Qddfcolh.Qddfch1;
      FLDA0100.colHdg2 = Qdb_Qddfcolh.Qddfch2;
      FLDA0100.colHdg3 = Qdb_Qddfcolh.Qddfch3;
    endif;

    FLDA0100.datTimFmt = f_intToExtDatTimFmt(Qdb_Qddffld.Qddfftyp :
                                             Qdb_Qddffld.Qddfdttf );

    FLDA0100.datTimSep = f_intToExtDatTimSep(Qdb_Qddffld.Qddfftyp :
                                             Qdb_Qddffld.Qddfdtts );

    // Set additional fields of format FLDA0200
    if   format = 'FLDA0200' or
         format = 'FLDA0300' or
         format = 'FLDA0310' or
         format = 'FLDA0320' or
         format = 'FLDA0330' or
         format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0200;
      FLDA0200 = FLDA0100;

      // If there are reference information
      if   pQdb_Qddfrefi <> *NULL;
        FLDA0200.refFile = Qdb_Qddfrefi.Qddfrfil;
        FLDA0200.refLib  = Qdb_Qddfrefi.Qddfrlib;
        FLDA0200.refFmt  = Qdb_Qddfrefi.Qddfrfmt;
        FLDA0200.refFld  = Qdb_Qddfrefi.Qddfrfld;
      else;
        FLDA0200.refFile = '';
        FLDA0200.refLib  = '';
        FLDA0200.refFmt  = '';
        FLDA0200.refFld  = '';
      endif;

    endif;

    // Set additional fields of format FLDA0300
    if   format = 'FLDA0300' or
         format = 'FLDA0310' or
         format = 'FLDA0320' or
         format = 'FLDA0330' or
         format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0300;
      FLDA0300 = FLDA0200;

      if f_isBitOn(x'80': qdb_qddffld.Qddffldst2);
        FLDA0300.alwNull = cTrue;
      else;
        FLDA0300.alwNull = cFalse;
      endif;

      FLDA0300.ccsid = qdb_qddffld.Qddfcsid;
    endif;

    // Set additional fields of format FLDA0310
    if   format = 'FLDA0310' or
         format = 'FLDA0320' or
         format = 'FLDA0330' or
         format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0310;
      FLDA0310 = FLDA0300;

      if isVarying;
        FLDA0310.varLength  = cTrue;
        FLDA0310.buffLength = Qdb_Qddffld.Qddffldb;
        FLDA0310.alcLength  = Qdb_Qddffld.Qddflalc;
      else;
        FLDA0310.varLength  = cFalse;
        FLDA0310.buffLength = Qdb_Qddffld.Qddffldb;
        FLDA0310.alcLength  = Qdb_Qddffld.Qddflalc;
      endif;
    endif;

    // Set additional fields of format FLDA0320
    if   format = 'FLDA0320' or
         format = 'FLDA0330' or
         format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0320;
      FLDA0320 = FLDA0310;
      FLDA0320.alias = longFldName;
    endif;

    // Set additional fields of format FLDA0330
    if   format = 'FLDA0330' or
         format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0330;
      FLDA0330 = FLDA0320;
      FLDA0330.fieldNum = Qdb_Qddfmt.Qddffldnum;
    endif;

    // Set additional fields of format FLDA0340
    if   format = 'FLDA0340' or
         format = 'FLDA0350';
      clear   FLDA0340;
      FLDA0340 = FLDA0330;
      if (pQdb_Qddfdft = *NULL);
        FLDA0340.lenDftValue   = 0;
        FLDA0340.pDftValue     = *NULL;
        FLDA0340.isDbcsGraphic = cFalse;
        FLDA0340.isHexLiteral  = cFalse;
        FLDA0340.isNullDft     = cFalse;
        FLDA0340.isCurrTime    = cFalse;
        FLDA0340.hasDtfKeyword = cFalse;
      else;
        FLDA0340.lenDftValue  =
              Qdb_Qddfdft.Qddfdftl - %size(Qdb_Qddfdft);
        FLDA0340.pDftValue    =
              %addr(Qdb_Qddfdft) + %size(Qdb_Qddfdft);
        FLDA0340.isDbcsGraphic =
              f_isBitOn(x'80':Qdb_Qddfdft.Qddfdfta);
        FLDA0340.isHexLiteral  =
              f_isBitOn(x'40':Qdb_Qddfdft.Qddfdfta);
        FLDA0340.isNullDft     =
              f_isBitOn(x'20':Qdb_Qddfdft.Qddfdfta);
        FLDA0340.isCurrTime    =
              f_isBitOn(x'04':Qdb_Qddfdft.Qddfdfta);
        FLDA0340.hasDtfKeyword =
              f_isBitOn(x'01':Qdb_Qddfdft.Qddfdfta);
      endif;
    endif;

    // Set additional fields of format FLDA0350
    if   format = 'FLDA0350';
      clear FLDA0350;
      FLDA0350 = FLDA0340;
      if (f_isBitOn(x'0400': Qdb_Qdbfh.Qdb_Qdbfidfl)); // file: has identity column?
        if (f_isBitOn(x'04': Qdb_Qddffld.Qddflagco)); // field: is identity column?
          pQdb_Qddfidcl = pQdb_Qddfmt + Qdb_Qddfmt.Qddf_Identity_Off;
          FLDA0350.isIdyCol = cTrue;
          FLDA0350.orgStrValue = Qdb_Qddfidcl.Qddf_Id_Orig_Start_With;
          FLDA0350.currStrValue = Qdb_Qddfidcl.Qddf_Id_Curr_Start_With;
          FLDA0350.incValue = Qdb_Qddfidcl.Qddf_Id_Increment_By;
          FLDA0350.minValue = Qdb_Qddfidcl.Qddf_Id_Minimum;
          FLDA0350.maxValue = Qdb_Qddfidcl.Qddf_Id_Maximum;
          FLDA0350.numCache = Qdb_Qddfidcl.Qddf_Id_Curr_Cache;
          FLDA0350.isCycling = Qdb_Qddfidcl.Qddf_Id_Cycle;
          FLDA0350.isOrdering = Qdb_Qddfidcl.Qddf_Id_Order;
        else;
          FLDA0350.isIdyCol = cFalse;
          FLDA0350.orgStrValue = 0;
          FLDA0350.currStrValue = 0;
          FLDA0350.incValue = 0;
          FLDA0350.minValue = 0;
          FLDA0350.maxValue = 0;
          FLDA0350.numCache = 0;
          FLDA0350.isCycling = cFalse;
          FLDA0350.isOrdering = cFalse;
        endif;
      else;
        FLDA0350.isIdyCol = cFalse;
      endif;
    endif;

    // Return format to caller
    select;
    when   format = 'FLDA0100';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0100;
    when   format = 'FLDA0200';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0200;
    when   format = 'FLDA0300';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0300;
    when   format = 'FLDA0310';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0310;
    when   format = 'FLDA0320';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0320;
    when   format = 'FLDA0330';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0330;
    when   format = 'FLDA0340';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0340;
    when   format = 'FLDA0350';
      %subst(o_data: 1: si_o_data.currLen) = FLDA0350;
    other;
      %subst(o_data: 1: si_o_data.currLen) = '';
    endsl;

    // Remember last field information
    handle.lastFldNum = fldNum;
    handle.lastFldPtr = pQdb_Qddffld;
  endif;

  return   o_isDone;


end-proc;

//======================================================================================
//  Get number of entries available
//======================================================================================
/define UNDEFINE_ALL
/undefine UNDEFINE_ALL

dcl-proc f_FldDct_getNumE export;
  dcl-pi *n int(10);
    i_handle like(fldDct_handle_t) const;
  end-pi;

  //  Return value
  dcl-s numEntries int(10) inz;

  //  Handle
  dcl-ds handle likeds(handle_t) based(pHandle);

  //  Format Definition Header (Qdb_Qddfmt)
  dcl-ds Qdb_Qddfmt likeds(Qdb_Qddfmt_t) based(pQdb_Qddfmt);
  // ---------------------------------------------------------


  // Einblenden Handle
  pHandle = i_handle;

  // Erm glichen Zugriff auf "Format Definition Header"
  pQdb_Qddfmt = handle.hFild0200;

  // Ermitteln Anzahl Felder
  numEntries = Qdb_Qddfmt.Qddffldnum;

  return   numEntries;


end-proc;

//======================================================================================
//  Returns cTrue if a given handle is NULL, else cFalse.
//======================================================================================
/define UNDEFINE_ALL
/undefine UNDEFINE_ALL

dcl-proc f_FldDct_isNull export;
  dcl-pi *n ind;
    i_handle like(fldDct_handle_t) const;
  end-pi;

  //  Handle
  dcl-ds handle likeds(handle_t) based(pHandle);
  // ---------------------------------------------------------


  if (i_handle = *NULL);
    return cTrue;
  else;
    return cFalse;
  endif;


end-proc;

//======================================================================================
//  Returns a NULL handle.
//======================================================================================
/define UNDEFINE_ALL
/undefine UNDEFINE_ALL

dcl-proc f_FldDct_null export;
  dcl-pi *n like(fldDct_handle_t);
  end-pi;
  // ---------------------------------------------------------


  return *NULL;


end-proc;

//==================================================================*
//  Convert internal data type to external representation
//==================================================================*

dcl-proc f_intToExtDataType;
  dcl-pi *n char(1);
    i_intDataType char(2) const;
  end-pi;

  //  Return value
  dcl-s o_extDataType char(1) inz;
  //-------------------------------------------------------------------

  select;
  // Binary
  when   i_inTDataType = X'0000';
    o_extDataType = cFLDDCT_TYPE_BINARY;
  // Float
  when   i_inTDataType = X'0001';
    o_extDataType = cFLDDCT_TYPE_FLOAT;
  // Zoned decimal
  when   i_inTDataType = X'0002';
    o_extDataType = cFLDDCT_TYPE_ZONED;
  // Packed decimal
  when   i_inTDataType = X'0003';
    o_extDataType = cFLDDCT_TYPE_PACKED;
  // Character
  when   i_inTDataType = X'0004';
    o_extDataType = cFLDDCT_TYPE_CHAR;
  // Var Character
  when   i_inTDataType = X'8004';
    o_extDataType = cFLDDCT_TYPE_CHAR;
  // Graphic
  when   i_inTDataType = X'0005';
    o_extDataType = cFLDDCT_TYPE_GRAPHIC;
  // DBCS-capable (not yet supported)
  when   i_inTDataType = X'0006';
    o_extDataType = cFLDDCT_TYPE_ERROR;
  // Large object CLOB/BLOB
  when   i_inTDataType = X'4004';
    o_extDataType = cFLDDCT_TYPE_LOB;
  // Var graphic
  when   i_inTDataType = X'8005';
    o_extDataType = cFLDDCT_TYPE_GRAPHIC;
  // Var DBCS-capable (not yet supported)
  when   i_inTDataType = X'8006';
    o_extDataType = cFLDDCT_TYPE_ERROR;
  // Date
  when   i_inTDataType = X'000B';
    o_extDataType = cFLDDCT_TYPE_DATE;
  // Time
  when   i_inTDataType = X'000C';
    o_extDataType = cFLDDCT_TYPE_TIME;
  // Timestamp
  when   i_inTDataType = X'000D';
    o_extDataType = cFLDDCT_TYPE_TMSTMP;
  // NULL (not yet supported)
  when   i_inTDataType = X'FFFF';
    o_extDataType = cFLDDCT_TYPE_ERROR;
  // unknown data type
  other;
    o_extDataType = cFLDDCT_TYPE_ERROR;
  endsl;

  return   o_extDataType;


end-proc;

//==================================================================*
//  Convert internal usage to to external representation
//==================================================================*

dcl-proc f_intToExtUsage;
  dcl-pi *n char(1);
    i_intUsage char(1) const;
  end-pi;

  //  Return value
  dcl-s o_extUsage char(1) inz;
  //-------------------------------------------------------------------

  select;
  // Input
  when   i_intUsage = X'01';
    o_extUsage = cFLDDCT_USE_INPUT;
  // Output
  when   i_intUsage = X'02';
    o_extUsage = cFLDDCT_USE_OUTPUT;
  // Both input and output
  when   i_intUsage = X'03';
    o_extUsage = cFLDDCT_USE_BOTH;
  // Neither
  when   i_intUsage = X'04';
    o_extUsage = cFLDDCT_USE_NEITHER;
  // unbekannte Verwendung
  other;
    o_extUsage = cFLDDCT_USE_ERROR;
  endsl;

  return   o_extUsage;


end-proc;

//==================================================================*
//  Convert internal date/time format to external representation
//==================================================================*

dcl-proc f_intToExtDatTimFmt;
  dcl-pi *n char(4);
    i_intDataType char(2) const;
    i_intFmt      char(1) const;
  end-pi;

  //  Return value
  dcl-s o_extFmt char(4) inz;
  //-------------------------------------------------------------------

  if   i_intDataType = X'000B'   or   // = Date
       i_intDataType = X'000C'   or   // = Time
       i_intDataType = X'000D';       // = Timestamp

    select;
    // The format associated with the job
    when   i_intFmt = X'FE';
      o_extFmt = cFLDDCT_DTFMT_JOB;
    // The format associated with the QDT
    when   i_intFmt = X'FF';
      o_extFmt = cFLDDCT_DTFMT_QDT;
    // *USA
    when   i_intFmt = X'01';
      o_extFmt = cFLDDCT_DTFMT_USA;
    // *ISO
    when   i_intFmt = X'03';
      o_extFmt = cFLDDCT_DTFMT_ISO;
    // *EUR
    when   i_intFmt = X'05';
      o_extFmt = cFLDDCT_DTFMT_EUR;
    // *JIS
    when   i_intFmt = X'07';
      o_extFmt = cFLDDCT_DTFMT_JIS;
    // SAA Timestamp
    when   i_intFmt = X'09';
      o_extFmt = cFLDDCT_DTFMT_SAA;
    // *MDY
    when   i_intFmt = X'17';
      o_extFmt = cFLDDCT_DTFMT_MDY;
    // *DMY
    when   i_intFmt = X'18';
      o_extFmt = cFLDDCT_DTFMT_DMY;
    // *YMD
    when   i_intFmt = X'19';
      o_extFmt = cFLDDCT_DTFMT_YMD;
    // *JUL
    when   i_intFmt = X'1A';
      o_extFmt = cFLDDCT_DTFMT_JUL;
    // *HMS
    when   i_intFmt = X'1B';
      o_extFmt = cFLDDCT_DTFMT_HMS;
    // CMDY
    when   i_intFmt = X'25';
      o_extFmt = cFLDDCT_DTFMT_CMDY;
    // CDMY
    when   i_intFmt = X'26';
      o_extFmt = cFLDDCT_DTFMT_CDMY;
    // CYMD
    when   i_intFmt = X'27';
      o_extFmt = cFLDDCT_DTFMT_CYMD;
    // MDYY
    when   i_intFmt = X'28';
      o_extFmt = cFLDDCT_DTFMT_MDYY;
    // *DMYY
    when   i_intFmt = X'29';
      o_extFmt = cFLDDCT_DTFMT_DMYY;
    // *YYMD
    when   i_intFmt = X'2A';
      o_extFmt = cFLDDCT_DTFMT_YYMD;
    // *YM
    when   i_intFmt = X'2B';
      o_extFmt = cFLDDCT_DTFMT_YM;
    // *MY
    when   i_intFmt = X'2C';
      o_extFmt = cFLDDCT_DTFMT_MY;
    // *YYM
    when   i_intFmt = X'2D';
      o_extFmt = cFLDDCT_DTFMT_YYM;
    // *MYY
    when   i_intFmt = X'2E';
      o_extFmt = cFLDDCT_DTFMT_MYY;
    // *LONGJUL
    when   i_intFmt = X'30';
      o_extFmt = cFLDDCT_DTFMT_LONGJUL;
    // unbekanntes Format
    other;
      o_extFmt = cFLDDCT_DTFMT_ERROR;
    endsl;

  else;
    o_extFmt = '';
  endif;

  return   o_extFmt;


end-proc;

//==================================================================*
//  Convert internal date/time separator to external representation
//==================================================================*

dcl-proc f_intToExtDatTimSep;
  dcl-pi *n char(1);
    i_intDataType char(2) const;
    i_intSep      char(1) const;
  end-pi;

  //  Return value
  dcl-s o_extSep char(1) inz;
  //-------------------------------------------------------------------

  if   i_intDataType = X'000B'   or   // = Date
       i_intDataType = X'000C'   or   // = Time
       i_intDataType = X'000D';       // = Timestamp

    select;
    // The format associated with the job
    when   i_intSep = X'00';
      o_extSep = cFLDDCT_DTSEP_JOB;
    // The implied separator is used
    when   i_intSep = X'EE';
      o_extSep = cFLDDCT_DTSEP_IMPL;
    // The slash ('/') ist used
    when   i_intSep = '/';
      o_extSep = cFLDDCT_DTSEP_SLASH;
    // The dash ('-') ist used
    when   i_intSep = '-';
      o_extSep = cFLDDCT_DTSEP_DASH;
    // The period ('.') ist used
    when   i_intSep = '.';
      o_extSep = cFLDDCT_DTSEP_PERIOD;
    // The blank (' ') ist used
    when   i_intSep = ' ';
      o_extSep = cFLDDCT_DTSEP_BLANK;
    // The colon (':') ist used
    when   i_intSep = ':';
      o_extSep = cFLDDCT_DTSEP_COLON;
    // unknown date/time separator
    other;
      o_extSep = cFLDDCT_DTSEP_ERROR;
    endsl;

  else;
    o_extSep = '';
  endif;

  return   o_extSep;


end-proc;
